const WAVE_HI = "M0,48 C50,14 100,14 150,48 C200,82 250,82 300,48 C350,14 400,14 450,48 C500,82 550,82 600,48 C650,14 700,14 750,48 C800,82 850,82 900,48 C950,14 1000,14 1050,48 C1100,82 1150,82 1200,48";
const WAVE_LO = "M0,48 C50,66 100,66 150,48 C200,30 250,30 300,48 C350,66 400,66 450,48 C500,30 550,30 600,48 C650,66 700,66 750,48 C800,30 850,30 900,48 C950,66 1000,66 1050,48 C1100,30 1150,30 1200,48";

function Tides() {
  return (
    <div style={{ position: "relative", height: 96, overflow: "hidden", margin: "8px 0 10px" }} aria-hidden>
      <svg className="wave wave-a" width="2400" height="96" viewBox="0 0 2400 96" style={{ position: "absolute", left: 0, top: 0 }}>
        <path d={WAVE_HI} fill="none" stroke="#C2566F" strokeWidth="1.8" opacity="0.9" />
        <path d={WAVE_HI} transform="translate(1200,0)" fill="none" stroke="#C2566F" strokeWidth="1.8" opacity="0.9" />
      </svg>
      <svg className="wave wave-b" width="2400" height="96" viewBox="0 0 2400 96" style={{ position: "absolute", left: 0, top: 0 }}>
        <path d={WAVE_LO} fill="none" stroke="#4B7A96" strokeWidth="1.8" opacity="0.85" />
        <path d={WAVE_LO} transform="translate(1200,0)" fill="none" stroke="#4B7A96" strokeWidth="1.8" opacity="0.85" />
      </svg>
    </div>
  );
}

