// currentColor (= hue зоны), в тон тонким волнам-сигнатуре сайта. Ключ = item.name.

function hexA(hex, a) {
  const n = parseInt(hex.slice(1), 16);
  return `rgba(${(n >> 16) & 255},${(n >> 8) & 255},${n & 255},${a})`;
}

