  "Тантра-группы мягкого спектра": (<><circle cx="8" cy="10" r="3"/><circle cx="16" cy="10" r="3"/><circle cx="8" cy="10" r=".9" fill="currentColor" stroke="none"/><circle cx="16" cy="10" r=".9" fill="currentColor" stroke="none"/><path d="M11 10h2"/><path d="M6 17c2 1.5 10 1.5 12 0" opacity=".5"/></>),
  "Телесно-ориентированная терапия": (<><circle cx="12" cy="5.3" r="2"/><path d="M12 7.3v8"/><path d="M8 11c2.7 1.2 5.3 1.2 8 0"/><path d="M12 15.3 9.5 20M12 15.3 14.5 20"/><circle cx="12" cy="10.8" r="1.6"/></>),
