  "Лингам- и йони-массаж": (<><path d="M12 16c-3.2 0-6.2-2-7.2-5 2-.5 4.2.5 5.2 2.2M12 16c3.2 0 6.2-2 7.2-5-2-.5-4.2.5-5.2 2.2"/><path d="M9.8 13c-.3-2.6.6-5 2.2-7 1.6 2 2.5 4.4 2.2 7"/><path d="M12 5.5c1 1.2 1.5 2 1.5 2.8a1.5 1.5 0 0 1-3 0c0-.8.5-1.6 1.5-2.8z" fill="currentColor" stroke="none"/></>),
