  "БДСМ-клубы и мунхи": (<><path d="M4 9c3-1 6-1 8 .3 2-1.3 5-1.3 8-.3.4 3-1.2 5.2-3.7 5.2-1.7 0-2.8-1.1-4.3-1.1s-2.6 1.1-4.3 1.1C5.2 14.2 3.6 12 4 9z"/><circle cx="8" cy="10.5" r=".9" fill="currentColor" stroke="none"/><circle cx="16" cy="10.5" r=".9" fill="currentColor" stroke="none"/></>),
  "Шибари": (<><path d="M12 3.5v17M5.5 8l13 8M18.5 8l-13 8"/><path d="M9 10.5c1.6 1.4 4.4 1.4 6 0M9 13.5c1.6-1.4 4.4-1.4 6 0"/></>),
  "Свинг и секс-позитивные вечеринки": (<><circle cx="8.5" cy="10" r="3.1"/><circle cx="15.5" cy="10" r="3.1"/><circle cx="12" cy="15.5" r="3.1"/></>),
  "Тантра глубокого спектра": (<><path d="M12 16c-3.2 0-6.2-2-7.2-5 2-.5 4.2.5 5.2 2.2M12 16c3.2 0 6.2-2 7.2-5-2-.5-4.2.5-5.2 2.2"/><path d="M12 4c1.6 2.2 2.6 3.8 2.6 5.3a2.6 2.6 0 0 1-5.2 0C9.4 7.8 10.4 6.2 12 4z"/></>),
